    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        //     {
        //         "base": "string",
        //         "completed_timestamp": "string",
        //         "counter": "string",
        //         "creation_timestamp": "string",
        //         "expiration_timestamp": "string",
        //         "fee_base": "string",
        //         "fee_counter": "string",
        //         "limit_price": "string",
        //         "limit_volume": "string",
        //         "order_id": "string",
        //         "pair": "string",
        //         "state": "PENDING",
        //         "type": "BID"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(order, "creation_timestamp");
        Object status = this.parseOrderStatus(this.safeString(order, "state"));
        status = ((Helpers.isTrue((Helpers.isEqual(status, "open"))))) ? status : status;
        Object side = null;
        Object orderType = this.safeString(order, "type");
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(orderType, "ASK"))) || Helpers.isTrue((Helpers.isEqual(orderType, "SELL")))))
        {
            side = "sell";
        } else if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(orderType, "BID"))) || Helpers.isTrue((Helpers.isEqual(orderType, "BUY")))))
        {
            side = "buy";
        }
        Object marketId = this.safeString(order, "pair");
        market = this.safeMarket(marketId, market);
        Object price = this.safeString(order, "limit_price");
        Object amount = this.safeString(order, "limit_volume");
        Object quoteFee = this.safeNumber(order, "fee_counter");
        Object baseFee = this.safeNumber(order, "fee_base");
        Object filled = this.safeString(order, "base");
        Object cost = this.safeString(order, "counter");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(quoteFee, null)))
        {
            final Object finalQuoteFee = quoteFee;
            final Object finalMarket = market;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalQuoteFee );
                put( "currency", Helpers.GetValue(finalMarket, "quote") );
            }};
        } else if (Helpers.isTrue(!Helpers.isEqual(baseFee, null)))
        {
            final Object finalBaseFee = baseFee;
            final Object finalMarket_2 = market;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalBaseFee );
                put( "currency", Helpers.GetValue(finalMarket_2, "base") );
            }};
        }
        Object id = this.safeString(order, "order_id");
        final Object finalStatus = status;
        final Object finalMarket_3 = market;
        final Object finalSide = side;
        final Object finalFee = fee;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "clientOrderId", null );
            put( "datetime", LunoCore.this.iso8601(timestamp) );
            put( "timestamp", timestamp );
            put( "lastTradeTimestamp", null );
            put( "status", finalStatus );
            put( "symbol", Helpers.GetValue(finalMarket_3, "symbol") );
            put( "type", null );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "side", finalSide );
            put( "price", price );
            put( "triggerPrice", null );
            put( "amount", amount );
            put( "filled", filled );
            put( "cost", cost );
            put( "remaining", null );
            put( "trades", null );
            put( "fee", finalFee );
            put( "info", order );
            put( "average", null );
        }}, market);
    }

