    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (public)
        //
        //      {
        //          "sequence":276989,
        //          "timestamp":1648651276949,
        //          "price":"35773.20000000",
        //          "volume":"0.00300000",
        //          "is_buy":false
        //      }
        //
        // fetchMyTrades (private)
        //
        //      {
        //          "pair":"LTCXBT",
        //          "sequence":3256813,
        //          "order_id":"BXEX6XHHDT5EGW2",
        //          "type":"ASK",
        //          "timestamp":1648652135235,
        //          "price":"0.002786",
        //          "volume":"0.10",
        //          "base":"0.10",
        //          "counter":"0.0002786",
        //          "fee_base":"0.0001",
        //          "fee_counter":"0.00",
        //          "is_buy":false,
        //          "client_order_id":""
        //      }
        //
        // For public trade data (is_buy === True) indicates 'buy' side but for private trade data
        // is_buy indicates maker or taker. The value of "type" (ASK/BID) indicate sell/buy side.
        // Private trade data includes ID field which public trade data does not.
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object orderId = this.safeString(trade, "order_id");
        Object id = this.safeString(trade, "sequence");
        Object takerOrMaker = null;
        Object side = null;
        if (Helpers.isTrue(!Helpers.isEqual(orderId, null)))
        {
            Object type = this.safeString(trade, "type");
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(type, "ASK"))) || Helpers.isTrue((Helpers.isEqual(type, "SELL")))))
            {
                side = "sell";
            } else if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(type, "BID"))) || Helpers.isTrue((Helpers.isEqual(type, "BUY")))))
            {
                side = "buy";
            }
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(side, "sell")) && Helpers.isTrue(Helpers.GetValue(trade, "is_buy"))))
            {
                takerOrMaker = "maker";
            } else if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(side, "buy")) && !Helpers.isTrue(Helpers.GetValue(trade, "is_buy"))))
            {
                takerOrMaker = "maker";
            } else
            {
                takerOrMaker = "taker";
            }
        } else
        {
            side = ((Helpers.isTrue(Helpers.GetValue(trade, "is_buy")))) ? "buy" : "sell";
        }
        Object feeBaseString = this.safeString(trade, "fee_base");
        Object feeCounterString = this.safeString(trade, "fee_counter");
        Object feeCurrency = null;
        Object feeCost = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeBaseString, null)))
        {
            if (!Helpers.isTrue(Precise.stringEquals(feeBaseString, "0.0")))
            {
                feeCurrency = this.safeString(market, "base");
                feeCost = feeBaseString;
            }
        } else if (Helpers.isTrue(!Helpers.isEqual(feeCounterString, null)))
        {
            if (!Helpers.isTrue(Precise.stringEquals(feeCounterString, "0.0")))
            {
                feeCurrency = this.safeString(market, "quote");
                feeCost = feeCounterString;
            }
        }
        Object timestamp = this.safeInteger(trade, "timestamp");
        final Object finalOrderId = orderId;
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalFeeCost = feeCost;
        final Object finalFeeCurrency = feeCurrency;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", id );
            put( "timestamp", timestamp );
            put( "datetime", LunoCore.this.iso8601(timestamp) );
            put( "symbol", LunoCore.this.safeString(market, "symbol") );
            put( "order", finalOrderId );
            put( "type", null );
            put( "side", finalSide );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", LunoCore.this.safeString(trade, "price") );
            put( "amount", LunoCore.this.safeString2(trade, "volume", "base") );
            put( "cost", LunoCore.this.safeString(trade, "counter") );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", finalFeeCurrency );
            }} );
        }}, market);
    }

