    /**
     * @method
     * @name luno#fetchOHLCV
     * @see https://www.luno.com/en/developers/api#tag/Market/operation/GetCandles
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} params extra parameters specific to the luno api endpoint
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "duration", LunoCore.this.safeValue(LunoCore.this.timeframes, timeframe, timeframe) );
                put( "pair", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "since", this.parseToInt(since));
            } else
            {
                Object duration = Helpers.multiply(Helpers.multiply(1000, 1000), this.parseTimeframe(timeframe));
                Helpers.addElementToObject(request, "since", Helpers.subtract(this.milliseconds(), duration));
            }
            Object response = (this.exchangePrivateGetCandles(this.extend(request, parameters))).join();
            //
            //     {
            //          "candles": [
            //              {
            //                  "timestamp": 1664055240000,
            //                  "open": "19612.65",
            //                  "close": "19612.65",
            //                  "high": "19612.65",
            //                  "low": "19612.65",
            //                  "volume": "0.00"
            //              },...
            //          ],
            //          "duration": 60,
            //          "pair": "XBTEUR"
            //     }
            //
            Object ohlcvs = this.safeList(response, "candles", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOHLCVs(ohlcvs, market, timeframe, since, limit);
        });

    }

    public Object parseOHLCV(Object ohlcv, Object... optionalArgs)
    {
        // {
        //     "timestamp": 1664055240000,
        //     "open": "19612.65",
        //     "close": "19612.65",
        //     "high": "19612.65",
        //     "low": "19612.65",
        //     "volume": "0.00"
        // }
        Object market = Helpers.getArg(optionalArgs, 0, null);
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger(ohlcv, "timestamp"), this.safeNumber(ohlcv, "open"), this.safeNumber(ohlcv, "high"), this.safeNumber(ohlcv, "low"), this.safeNumber(ohlcv, "close"), this.safeNumber(ohlcv, "volume")));
    }

    /**
     * @method
     * @name luno#fetchMyTrades
     * @description fetch all trades made by the user
     * @see https://www.luno.com/en/developers/api#tag/Orders/operation/ListUserTrades
     * @param {string} symbol unified market symbol
     * @param {int} [since] the earliest time in ms to fetch trades for
     * @param {int} [limit] the maximum number of trades structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchMyTrades() requires a symbol argument")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "pair", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "since", since);
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            Object response = (this.privateGetListtrades(this.extend(request, parameters))).join();
            //
            //      {
            //          "trades":[
            //              {
            //                  "pair":"LTCXBT",
            //                  "sequence":3256813,
            //                  "order_id":"BXEX6XHHDT5EGW2",
            //                  "type":"ASK",
            //                  "timestamp":1648652135235,
            //                  "price":"0.002786",
            //                  "volume":"0.10",
            //                  "base":"0.10",
            //                  "counter":"0.0002786",
            //                  "fee_base":"0.0001",
            //                  "fee_counter":"0.00",
            //                  "is_buy":false,
            //                  "client_order_id":""
            //              },...
            //          ]
            //      }
            //
            Object trades = this.safeList(response, "trades", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseTrades(trades, market, since, limit);
        });

    }

